1	const repeat = <T>(value: T, times: number): T[] => Array(times).fill(value);
2	
3	export function scalePixelArt(image: string[][], scaleFactor: number): string[][] {
4	  if (image.length === 0) return [];
5	  if (scaleFactor === 1) return image;
6	  const scaledRow = image[0].flatMap(pixel => repeat(pixel, scaleFactor));
7	  return repeat(scaledRow, scaleFactor);
8	}
